beforeSaveCustomScript:
if (entity\isAttributeChanged('peResearchStatus') && peResearchStatus == 'COMPLETED') {
    outreachStatus = 'RESEARCH_COMPLETED';
}
if (entity\isAttributeChanged('peOpportunityScoreV4') && peOpportunityScoreV4 >= 80) {
    pePriorityLevel = 'HIGH';
}
if ((entity\isAttributeChanged('emailAddress') && emailAddress != '') || (entity\isAttributeChanged('phoneNumber') && phoneNumber != '')) {
    if (outreachStatus == 'RESEARCH_COMPLETED' || outreachStatus == 'QUALIFIED') {
        outreachStatus = 'CONTACT_READY';
    }
}
